class FreteWidget extends StatefulWidget {
  final int vendaId;
  final int compradorId;
  final int peso;
  final Product product;
  final Negotiation negotiation;

  const FreteWidget({
    required this.vendaId,
    required this.compradorId,
    required this.peso,
    required this.product,
    required this.negotiation,
    Key? key,
  }) : super(key: key);

  @override
  _FreteWidgetState createState() => _FreteWidgetState();
}

class _FreteWidgetState extends State<FreteWidget> {
  late Future<double> _freteFuture;
  bool contratarFrete = false;
  final NumberFormat _formatter = NumberFormat.currency(
    locale: 'pt_BR',
    symbol: 'R\$',
    decimalDigits: 2,
  );

  Future<double> _calcularFrete() async {
    Map<String, dynamic> requestBody = {
      "vendaId": widget.vendaId,
      "compradorId": widget.compradorId,
      "peso": widget.peso,
      "isNegociacao": false,
    };
    
    try {
      return await CheckoutCaller.carregarVlrFrete(context, requestBody);
    } catch (e) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Erro ao calcular frete: ${e.toString()}')),
      );
      return 0.0;
    }
  }

  void _showFretePopup(double valorFrete) {
    showDialog(
      context: context,
      builder: (context) => AlertDialog(
        title: const Text('Detalhes do Frete'),
        content: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Text('Origem: ${widget.product.cidadeOrigem}'),
            Text('Destino: ${widget.negotiation.cidadeEntr}'),
            const SizedBox(height: 12),
            Text('Valor Total: ${_formatter.format(valorFrete)}'),
            Text('Peso: ${widget.peso} kg'),
            const SizedBox(height: 16),
            const Text(
              'Este é o valor estimado de frete. Será feita uma nova cotação junto aos motoristas parceiros para verificar se conseguiremos manter o preço.',
              style: TextStyle(fontSize: 12, color: Colors.grey),
            ),
          ],
        ),
        actions: [
          TextButton(
            child: const Text('Fechar'),
            onPressed: () => Navigator.of(context).pop(),
          ),
        ],
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return Container(
      padding: const EdgeInsets.all(15),
      decoration: BoxDecoration(
        color: Colors.white,
        borderRadius: BorderRadius.circular(15),
        border: Border.all(color: Colors.green[800]!.withOpacity(0.3)),
      ),
      child: Row(
        children: [
          Checkbox(
            value: contratarFrete,
            onChanged: (bool? value) async {
              setState(() => contratarFrete = value ?? false);
              if (contratarFrete) {
                final frete = await _calcularFrete();
                _showFretePopup(frete);
              }
            },
            activeColor: Colors.green[800],
          ),
          Expanded(
            child: FutureBuilder<double>(
              future: _freteFuture,
              builder: (context, snapshot) {
                if (snapshot.connectionState == ConnectionState.waiting) {
                  return const Text('Calculando frete...',
                      style: TextStyle(color: Colors.grey));
                }

                if (snapshot.hasError) {
                  return const Text('Frete não disponível',
                      style: TextStyle(color: Colors.red));
                }

                return Text(
                  'Contratar Frete - ${_formatter.format(snapshot.data ?? 0.0)}',
                  style: TextStyle(
                    fontWeight: FontWeight.bold,
                    color: Colors.green[800]
                  ),
                );
              },
            ),
          ),
        ],
      ),
    );
  }
}
